import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"猎人斧","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/猎人斧.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/猎人斧.md"}'),b={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/猎人斧.md"};function d(p,e,l,_,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"猎人斧",tabindex:"-1"},[s("猎人斧 "),r("a",{class:"header-anchor",href:"#猎人斧","aria-label":'Permalink to "猎人斧"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),o('<h1 id="猎人斧-1" tabindex="-1">猎人斧 <a class="header-anchor" href="#猎人斧-1" aria-label="Permalink to &quot;猎人斧&quot;">​</a></h1><p>猎人斧<br> 工厂诡兵器，一般用于猎杀行动，具有斧头的特质，变形之后可以施展多样化的攻击模式，可以使出强力的劈砍攻击，提高回复能力<br> 不论有怎样的过去，怪兽就是怪兽，有些人会选择用这把斧头来执行刀斧手的任务。</p><p>D+500<br> 武器类型：斧<br> 体积：3<br> 武器伤害：7L<br> 伤害类型：挥砍<br> 破防： 2破甲 1破魔<br> 效果：其外形是一把短柄斧，现在你可以使用一个花招动作从内置的机关中将斧柄拉长并固定，现在你只要满足基础的力量条件，该武器就可以变形为一把体积6，具有【双手】特性，且在格挡时额外获得2点格挡防御的长柄斧。</p><p>C+1000<br> 武器类型：斧<br> 体积：3<br> 武器伤害：12L<br> 伤害类型：挥砍<br> 破防：4破甲 3破魔<br> 效果：现在当你在双手斧状态下持有该武器时，你可以使用特殊技能回旋斩，现在你可以在持有双手斧状态下时令攻击鉴定作用于你触及范围内的所有敌方单位。</p><p>B+3000<br> 武器类型：斧<br> 体积：3<br> 武器伤害：22L<br> 伤害类型：挥砍<br> 破防：9破甲 8破魔，若该武器的破甲以及破魔属性结算后仍有剩余则转化为攻击上的增强加值，至多各转化5点。<br> 效果：你在使用这把武器进行格挡时获得【看破】特性，并且现在若你在进行攻击后立刻以花招动作切换武器形态，则你的下一次攻击附带【碾压】特性并且在攻击时获得1点力量检定上的附加成功。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(b,[["render",d]]);export{f as __pageData,m as default};
